from scipy import misc
import matplotlib.pyplot as plt
import numpy as np
from os import listdir
from sklearn import model_selection, preprocessing
from tensorflow.keras.models import Model
from tensorflow.keras.layers import Input, Dense, Flatten, Dropout, Activation
from tensorflow.keras.utils import to_categorical
from tensorflow.keras.applications.vgg16 import VGG16
from tensorflow.keras.preprocessing import image as kimage
from sklearn.metrics import accuracy_score, confusion_matrix


data = []
labels = []
classes = listdir('data/') # assuming each subdirectory inside 'data' is a class
for c in classes:
    print(c)
    class_path = f'data/{c}'
    print(class_path)
    images = listdir(class_path)
    for i, image_name in enumerate(images):
        if i%50 == 0 :
            print('processing %d' %(i+1), end='\r')
        img_arr = kimage.load_img(f'{class_path}/{image_name}', target_size=(28, 28))
        img_arr = kimage.img_to_array(img_arr)
        data.append(img_arr/255.) # normalize pixel values from 0-255 to 0-1
        labels.append(c)

data = np.array(data)
labels = np.array(labels)


encoder = preprocessing.LabelEncoder()
encoder.fit(labels)
y_train = encoder.transform(labels)
Y_train = to_categorical(y_train, 39) # we have 40 classes - 1 for each employee


# model
def createModel():
    model = VGG16()
    model.layers.pop()
    for layer in model.layers:
        layer.trainable = False

    input = Input(shape=(28, 28)) # input_tensor=image_input
    output = Flatten()(model.output) # flatten to 1d vector
    out = Dense(50)(output) # fully connected neural network
    out = Activation('relu')(out) # nonlinear activation - rectified linear unit (ReLU)
    output = Dropout(.5)(out)# dropout layer to avoid overfitting, set the probability of being dropped as .5. 
    predictions = Dense(39, activation='softmax')(output)

    return Model(inputs=model.input, outputs=predictions)

model = createModel()
model.compile('adam', loss="categorical_crossentropy", metrics=['accuracy'])


(xTrain, xTest, yTrain, yTest)= model_selection.train_test_split(data, Y_train, test_size=.20, random_state=1)
print("training")
model.fit(xTrain,yTrain,validation_split=.35, epochs=7, batch_size=24)


# get accuracy score on training set and test set
p_yhat = model.predict(data) # probability vector of 1s and 0s (one-hot encoding of predicted classes), each row is an image in the data input array.
yhat = np.argmax(p_yhat, axis=1)
print("train accuracy: ", round(accuracy_score(encoder.inverse_transform(np.argmax(Y_train, 1)), encoder.inverse_transform(yhat))*100), '%')


pTest_y = model.predict(xTest) # probability vector of 1s and 0s (one-hot encoding of predicted classes), each row is an image in the data input array.
yhat_test = np.argmax(pTest_y, axis=1)
print("validation accuracy: ", round(accuracy_score(encoder.inverse_transform(np.argmax(yTrain, 1)), encoder.inverse_transform(yhat))*100), '%')


cm = confusion_matrix(encoder.inverse_transform(np.argmax(Y_train, 1)), encoder.inverse_transform(yhat)) # matrix showing counts of each class predicted correctly and incorrectly for the train set.